// ---------------------------------------------------------------------------
// Validate GitHub webhook HMAC-SHA256 signature.
// n8n does not natively verify signatures, so we do it here.
// If validation fails the workflow exits early with a 401 log.
//
// NOTE: In production, pair this with an nginx rule that only allows
// requests from GitHub's published IP ranges (meta.github.com).
// ---------------------------------------------------------------------------
const crypto = require('crypto');

const secret    = $env.GITHUB_WEBHOOK_SECRET || '';
const rawBody   = $input.first().json._rawBody || '';
const sigHeader = $input.first().json.headers?.['x-hub-signature-256'] || '';

if (secret && sigHeader) {
  const hmac     = crypto.createHmac('sha256', secret);
  hmac.update(rawBody);
  const expected = 'sha256=' + hmac.digest('hex');
  if (!crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(sigHeader))) {
    throw new Error('GitHub webhook signature mismatch — request rejected');
  }
}

// Pass the parsed body forward
const body  = $input.first().json;
const event = body.headers?.['x-github-event'] || body['x-github-event'] || 'unknown';

return [{ json: { ...body, _githubEvent: event } }];

// ---------------------------------------------------------------------------
// Extract key fields from the GitHub payload and resolve the JIRA ticket.
//
// Convention: JIRA ticket ID appears in the PR title or body as [A-Z]+-\d+
// e.g.  "feat: add retry logic [CERT-123]"  or  "Fixes CERT-456"
//
// Retry note: this node is idempotent; n8n's built-in retry (max 3 attempts,
// exponential back-off) handles transient failures on the HTTP nodes below.
// ---------------------------------------------------------------------------
const body  = $input.first().json;
const event = body._githubEvent;

// Pull Request events
const pr       = body.pull_request || {};
const prNumber = pr.number         || body.number        || null;
const prTitle  = pr.title          || '';
const prBody   = pr.body           || '';
const prUrl    = pr.html_url       || '';
const prAction = body.action       || '';
const headSha  = pr.head?.sha      || body.after          || '';
const baseBranch = pr.base?.ref    || '';
const headBranch = pr.head?.ref    || '';

// Pull Request Review events
const review         = body.review || {};
const reviewState    = review.state       || '';   // approved | changes_requested | commented
const reviewerLogin  = review.user?.login || '';
const reviewBody     = review.body        || '';

// Check Suite events
const checkSuite        = body.check_suite || {};
const checkSuiteStatus  = checkSuite.status     || '';
const checkSuiteConclusion = checkSuite.conclusion || '';
const checkSuiteApp     = checkSuite.app?.name   || '';

// Repository
const repoFullName = body.repository?.full_name || `${$env.GITHUB_OWNER}/${$env.GITHUB_REPO}`;
const [repoOwner, repoName] = repoFullName.split('/');

// Extract JIRA ticket ID from PR title then body (first match wins)
const jiraRegex  = /([A-Z][A-Z0-9_]+-\d+)/g;
const titleMatch = prTitle.match(jiraRegex);
const bodyMatch  = prBody.match(jiraRegex);
const jiraTicket = (titleMatch?.[0] || bodyMatch?.[0] || '').toUpperCase();

// Requester
const senderLogin = body.sender?.login || 'unknown';

return [{
  json: {
    _githubEvent:          event,
    prNumber,
    prTitle,
    prUrl,
    prAction,
    headSha,
    baseBranch,
    headBranch,
    reviewState,
    reviewerLogin,
    reviewBody,
    checkSuiteStatus,
    checkSuiteConclusion,
    checkSuiteApp,
    repoOwner,
    repoName,
    repoFullName,
    jiraTicket,
    senderLogin
  }
}];

