// ---------------------------------------------------------------------------
// Structured log entry — emitted after every successful JIRA update.
// ---------------------------------------------------------------------------
const now  = new Date().toISOString();
const item = $input.first().json;

const logEntry = {
  timestamp:   now,
  source:      'github-to-jira-sync',
  github_event: item._githubEvent,
  github_pr:   item.prNumber   || 'N/A',
  jira_ticket: item.jiraTicket || 'N/A',
  action:      `${item._githubEvent}:${item.prAction || item.reviewState || item.checkSuiteConclusion}`,
  user:        item.reviewerLogin || item.senderLogin || 'unknown',
  repo:        item.repoFullName  || 'unknown',
  level:       'INFO'
};

console.log(JSON.stringify(logEntry));
return [{ json: logEntry }];

// No JIRA ticket found — log and exit cleanly.
const item = $input.first().json;
console.log(JSON.stringify({
  timestamp:    new Date().toISOString(),
  source:       'github-to-jira-sync',
  level:        'WARN',
  message:      'No JIRA ticket ID in PR title/body — skipping',
  github_event: item._githubEvent,
  github_pr:    item.prNumber,
  pr_title:     item.prTitle
}));
return [{ json: { skipped: true, reason: 'no_jira_ticket', prNumber: item.prNumber } }];

// Unhandled event type — log and exit cleanly.
const item = $input.first().json;
console.log(JSON.stringify({
  timestamp:    new Date().toISOString(),
  source:       'github-to-jira-sync',
  level:        'DEBUG',
  message:      'Unhandled GitHub event/action combination — no JIRA action taken',
  github_event: item._githubEvent,
  pr_action:    item.prAction
}));
return [{ json: { skipped: true, reason: 'unhandled_event', event: item._githubEvent } }];

// ---------------------------------------------------------------------------
// Error handler — catches failures from any upstream node.
// Retry note: n8n retries HTTP nodes up to 3 times (configured per node).
// If all retries fail, execution reaches here.
// ---------------------------------------------------------------------------
const error = $input.first().json;
console.error(JSON.stringify({
  timestamp: new Date().toISOString(),
  source:    'github-to-jira-sync',
  level:     'ERROR',
  message:   error.message || 'Unknown error',
  node:      error.node    || 'unknown',
  details:   error
}));
throw new Error(`[github-to-jira-sync] ${error.message || 'Workflow error'}`);
